  1591→			 VALUES ($1, $2, $3)
  1592→			 ON CONFLICT (provider, repository) DO NOTHING
  1593→			 RETURNING id, project_id, provider, repository, poll_interval_seconds, enabled, created_at, updated_at`,
  1594→			projectID, sel.Provider, sel.UpstreamRepo,
