	go h.pollSourceAsync(id, src.Provider, src.Repository)
	RespondJSON(w, r, http.StatusOK, src)
}

// Delete handles DELETE /sources/{id} — deletes a source.
func (h *SourcesHandler) Delete(w http.ResponseWriter, r *http.Request) {
