package ingestion

import (
	"bytes"
	"context"
	"encoding/json"
	"fmt"
	"net/http"
	"time"
)

const defaultECRPublicURL = "https://public.ecr.aws"
const ecrGalleryAPI = "https://api.us-east-1.gallery.ecr.aws"

// ECRPublicSource polls AWS ECR Public Gallery for new image tags
// using the ECR Public Gallery API which returns pushed timestamps directly.
type ECRPublicSource struct {
	client     *http.Client
	repository string // "registry_alias/repo_name", e.g. "i6b2w2n6/op-node"
	baseURL    string
	galleryURL string
	sourceID   string
}

func NewECRPublicSource(client *http.Client, repository string, sourceID string) *ECRPublicSource {
	return &ECRPublicSource{
		client:     client,
		repository: repository,
		baseURL:    defaultECRPublicURL,
		galleryURL: ecrGalleryAPI,
		sourceID:   sourceID,
	}
}

func (s *ECRPublicSource) Name() string    { return "ecr-public" }
func (s *ECRPublicSource) SourceID() string { return s.sourceID }

// ecrImageTagDetail represents a single tag from the ECR Gallery API response.
type ecrImageTagDetail struct {
	ImageTag string `json:"imageTag"`
	Detail   struct {
		ImagePushedAt string `json:"imagePushedAt"`
	} `json:"imageDetail"`
}

func (s *ECRPublicSource) FetchNewReleases(ctx context.Context) ([]IngestionResult, error) {
	// Parse "alias/repo" into separate fields for the Gallery API.
	alias, repo, err := splitRepository(s.repository)
	if err != nil {
		return nil, err
	}

	var allTags []ecrImageTagDetail
	var nextToken string

	for {
		tags, token, err := s.fetchImageTags(ctx, alias, repo, nextToken)
		if err != nil {
			return nil, fmt.Errorf("fetch image tags: %w", err)
		}
		allTags = append(allTags, tags...)
		if token == "" {
			break
		}
		nextToken = token
	}

	results := make([]IngestionResult, 0, len(allTags))
	for _, tag := range allTags {
		ts, _ := time.Parse(time.RFC3339Nano, tag.Detail.ImagePushedAt)
		if ts.IsZero() {
			ts = time.Now()
		}
		results = append(results, IngestionResult{
			Repository: s.repository,
			RawVersion: tag.ImageTag,
			Timestamp:  ts,
		})
	}
	return results, nil
}

// fetchImageTags calls the ECR Public Gallery API to list image tags with pushed timestamps.
func (s *ECRPublicSource) fetchImageTags(ctx context.Context, alias, repo, nextToken string) ([]ecrImageTagDetail, string, error) {
	payload := map[string]interface{}{
		"registryAliasName": alias,
		"repositoryName":    repo,
		"maxResults":        100,
	}
	if nextToken != "" {
		payload["nextToken"] = nextToken
	}

	body, err := json.Marshal(payload)
	if err != nil {
		return nil, "", err
	}

	req, err := http.NewRequestWithContext(ctx, http.MethodPost, s.galleryURL+"/describeImageTags", bytes.NewReader(body))
	if err != nil {
		return nil, "", err
	}
	req.Header.Set("Content-Type", "application/json")

	resp, err := s.client.Do(req)
	if err != nil {
		return nil, "", err
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return nil, "", fmt.Errorf("gallery API status %d", resp.StatusCode)
	}

	var result struct {
		ImageTagDetails []ecrImageTagDetail `json:"imageTagDetails"`
		NextToken       string              `json:"nextToken"`
	}
	if err := json.NewDecoder(resp.Body).Decode(&result); err != nil {
		return nil, "", err
	}
	return result.ImageTagDetails, result.NextToken, nil
}

// splitRepository splits "alias/repo" into its two components.
func splitRepository(repository string) (alias, repo string, err error) {
	for i, c := range repository {
		if c == '/' {
			return repository[:i], repository[i+1:], nil
		}
	}
	return "", "", fmt.Errorf("ecr-public repository must be alias/repo, got %q", repository)
}

"use client";

import useSWR from "swr";
import Link from "next/link";
import { useState, useRef, useEffect, useCallback } from "react";
import { useRouter } from "next/navigation";
import {
  projects as projectsApi,
  sources as sourcesApi,
  contextSources as ctxApi,
  agent as agentApi,
  releases as releasesApi,
} from "@/lib/api/client";
import type { AgentRules, Source } from "@/lib/api/types";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { ConfirmDialog } from "@/components/ui/confirm-dialog";
import { SourceForm } from "@/components/sources/source-form";
import { NewContextSourceForm } from "@/components/context-sources/new-context-source-form";
import { ProjectLogo } from "@/components/ui/project-logo";
import { ProviderBadge } from "@/components/ui/provider-badge";
import { StatusDot } from "@/components/ui/status-dot";
import { SectionLabel } from "@/components/ui/section-label";
import { formatInterval } from "@/lib/format";
import { getPathSegment } from "@/lib/path";
import { Pencil, Trash2, Play, Plus, ArrowLeft } from "lucide-react";

/* ---------- Tabs ---------- */

const tabs = [
  { key: "sources", label: "Sources" },
  { key: "context", label: "Context Sources" },
  { key: "agent", label: "Semantic Release Settings" },
] as const;

type TabKey = (typeof tabs)[number]["key"];

/* ---------- Helpers ---------- */

function formatDuration(startedAt?: string, completedAt?: string): string {
  if (!startedAt) return "--";
  const start = new Date(startedAt).getTime();
  const end = completedAt ? new Date(completedAt).getTime() : Date.now();
  const secs = Math.round((end - start) / 1000);
  if (secs < 60) return `${secs}s`;
  const mins = Math.floor(secs / 60);
  const rem = secs % 60;
  return `${mins}m ${rem}s`;
}

function truncate(str: string, max: number): string {
  return str.length > max ? str.slice(0, max) + "\u2026" : str;
}

/* ---------- Main component ---------- */

export function ProjectDetail() {
  // Read ID from URL path — useParams() returns stale "0" in static export
  const id = getPathSegment(1); // /projects/{id}
  const router = useRouter();
  const [activeTab, setActiveTab] = useState<TabKey>("sources");

  /* Test run state */
  const [testSourceId, setTestSourceId] = useState<string>("");
  const [testVersion, setTestVersion] = useState<string>("");
  const [testRunning, setTestRunning] = useState(false);

  /* Agent config local state */
  const [promptDraft, setPromptDraft] = useState<string | null>(null);
  const [rulesDraft, setRulesDraft] = useState<AgentRules | null>(null);
  const [saving, setSaving] = useState(false);

  /* Inline edit state */
  const [editingName, setEditingName] = useState(false);
  const [editingDesc, setEditingDesc] = useState(false);
  const [nameDraft, setNameDraft] = useState("");
  const [descDraft, setDescDraft] = useState("");
  const nameRef = useRef<HTMLInputElement>(null);
  const descRef = useRef<HTMLInputElement>(null);

  /* Dialog state */
  const [sourceCreateOpen, setSourceCreateOpen] = useState(false);
  const [editingSource, setEditingSource] = useState<Source | null>(null);
  const [deletingSourceId, setDeletingSourceId] = useState<string | null>(null);
  const [ctxCreateOpen, setCtxCreateOpen] = useState(false);
  const [deletingCtxId, setDeletingCtxId] = useState<string | null>(null);
  const [deletingProject, setDeletingProject] = useState(false);

  /* Data fetching */
  const { data, isLoading, mutate: mutateProject } = useSWR(`project-${id}`, () => projectsApi.get(id));
  const { data: sourcesData, mutate: mutateSources } = useSWR(
    `project-${id}-sources`,
    () => sourcesApi.listByProject(id),
  );
  const { data: ctxData, mutate: mutateCtx } = useSWR(
    `project-${id}-ctx`,
    () => ctxApi.list(id),
  );
  const { data: runsData, mutate: mutateRuns } = useSWR(
    activeTab === "agent" ? `project-${id}-runs` : null,
    () => agentApi.listRuns(id),
  );
  const { data: testReleasesData } = useSWR(
    testSourceId ? `source-${testSourceId}-releases` : null,
    () => releasesApi.listBySource(testSourceId, 1),
  );

  const saveName = useCallback(async () => {
    const p = data?.data;
    if (!p) return;
    const trimmed = nameDraft.trim();
    if (trimmed && trimmed !== p.name) {
      await projectsApi.update(id, { name: trimmed, description: p.description });
      mutateProject();
    }
    setEditingName(false);
  }, [nameDraft, data, id, mutateProject]);

  const saveDesc = useCallback(async () => {
    const p = data?.data;
    if (!p) return;
    const trimmed = descDraft.trim();
    if (trimmed !== (p.description ?? "")) {
      await projectsApi.update(id, { name: p.name, description: trimmed || undefined });
      mutateProject();
    }
    setEditingDesc(false);
  }, [descDraft, data, id, mutateProject]);

  /* Click-outside handlers */
  useEffect(() => {
    if (!editingName) return;
    const handler = (e: MouseEvent) => {
      if (nameRef.current && !nameRef.current.contains(e.target as Node)) saveName();
    };
    document.addEventListener("mousedown", handler);
    return () => document.removeEventListener("mousedown", handler);
  }, [editingName, saveName]);

  useEffect(() => {
    if (!editingDesc) return;
    const handler = (e: MouseEvent) => {
      if (descRef.current && !descRef.current.contains(e.target as Node)) saveDesc();
    };
    document.addEventListener("mousedown", handler);
    return () => document.removeEventListener("mousedown", handler);
  }, [editingDesc, saveDesc]);

  /* Handlers */
  const handleToggleSource = async (source: { id: string; provider: string; repository: string; poll_interval_seconds: number; enabled: boolean; config?: Record<string, unknown> }) => {
    await sourcesApi.update(source.id, {
      provider: source.provider,
      repository: source.repository,
      poll_interval_seconds: source.poll_interval_seconds,
      enabled: !source.enabled,
      config: source.config,
    });
    mutateSources();
  };

  const handleSaveAgentConfig = async () => {
    if (!project) return;
    setSaving(true);
    try {
      const input = {
        name: project.name,
        description: project.description,
        agent_prompt: promptDraft ?? project.agent_prompt,
        agent_rules: rulesDraft ?? project.agent_rules,
      };
      await projectsApi.update(id, input);
      mutateProject();
      setPromptDraft(null);
      setRulesDraft(null);
    } finally {
      setSaving(false);
    }
  };

  const handleTestRun = async () => {
    if (!testVersion) return;
    setTestRunning(true);
    try {
      await agentApi.triggerRun(id, testVersion);
      mutateRuns();
    } finally {
      setTestRunning(false);
    }
  };

  /* Loading / not found states */
  if (isLoading) {
    return (
      <div className="flex h-48 items-center justify-center" style={{ color: "#9ca3af" }}>
        Loading...
      </div>
    );
  }

  const project = data?.data;
  if (!project) {
    return (
      <div className="flex h-48 items-center justify-center" style={{ color: "#6b7280" }}>
        Project not found
      </div>
    );
  }

  /* Derived counts */
  const sourceCount = sourcesData?.data?.length;
  const ctxCount = ctxData?.data?.length;

  /* Current effective values */
  const currentPrompt = promptDraft ?? project.agent_prompt ?? "";
  const currentRules: AgentRules = rulesDraft ?? project.agent_rules ?? {};

  return (
    <div className="space-y-0">
      {/* ===== Header zone ===== */}
      <div
        className="-m-6 mb-0 border-b px-6 py-5"
        style={{ backgroundColor: "#ffffff", borderColor: "#e8e8e5" }}
      >
        {/* Back link */}
        <Link
